module custom_logic (
    input a,
    input b,
    input c,
    input d,
    output reg invalid_output);

    always @(*) begin
        case ({a, b, c, d})
            4'b1101: invalid_output = 1;
            4'b0011: invalid_output = 0;
            4'b1010: invalid_output = 0;
            4'b0100: invalid_output = 1;
            4'b1110: invalid_output = 0;
            4'b0111: invalid_output = 1;
            4'b1001: invalid_output = 0;
            4'b0010: invalid_output = 1;
            4'b1111: invalid_output = 0;
            4'b0101: invalid_output = 1;
            default: invalid_output = 0;
        endcase
    end
endmodule
